# Conditional Access policy targeting Owner-level activities:
# Require phishing-resistant MFA (FIDO2 / WHfB) for any write to Microsoft.Authorization/*

# Create a CA policy requiring strong auth for Azure management (requires P1 license)
$policy = @{
    displayName = 'Require strong auth for Azure management'
    state = 'enabled'
    conditions = @{
        cloudApps = @{
            includeApplications = @('797f4846-ba00-4fd7-ba43-dac1f8f63013')  # Windows Azure Service Mgmt
        }
        users = @{
            includeRoles = @('8e3af657-a8ff-443c-a75c-2fe8c4bcb635')  # Owner role
            excludeUsers = @('<break-glass-1-id>', '<break-glass-2-id>')
        }
    }
    grantControls = @{
        operator = 'OR'
        builtInControls = @('mfa')
        authenticationStrength = @{
            id = '00000000-0000-0000-0000-000000000004'  # Phishing-resistant MFA
        }
    }
}
New-MgIdentityConditionalAccessPolicy -BodyParameter $policy

# Additional policy: block Owner sign-in from outside named locations
# Combine with IP-named locations for on-premises or VPN ranges:
$locationPolicy = @{
    displayName = 'Block Owner from untrusted locations'
    state = 'enabled'
    conditions = @{
        users = @{ includeRoles = @('8e3af657-a8ff-443c-a75c-2fe8c4bcb635') }
        locations = @{ includeLocations = @('All'); excludeLocations = @('<named-location-id>') }
        cloudApps = @{ includeApplications = @('All') }
    }
    grantControls = @{ operator = 'OR'; builtInControls = @('block') }
}
New-MgIdentityConditionalAccessPolicy -BodyParameter $locationPolicy
